html:
{% set movie_name = frappe.db.get_value('Show', doc.show, 'movie') if doc.show else None %}
{% set poster = frappe.db.get_value('Movie', movie_name, 'poster') if movie_name else None %}
{% set qr_files = frappe.get_all('File', filters={'attached_to_doctype': 'Ticket Booking', 'attached_to_name': doc.name, 'file_name': ['like', '%-qr%.png']}, pluck='file_url', limit=1) %}
{% set qr_url = frappe.utils.get_url(qr_files[0]) if qr_files else None %}
{% set seats = ', '.join(doc.seats | map(attribute='seat_label') | list) %}

<style>
  @page { size: 220mm 100mm; margin: 0; }

  .ticket-wrap {
    font-family: 'Segoe UI', Arial, sans-serif;
    background: #1a1a2e;
    color: #eee;
    width: 100%;
    max-width: 800px;
    margin: 0 auto;
    border-radius: 16px;
    overflow: hidden;
    display: flex;
    position: relative;
  }

  /* Dashed perforation line */
  .ticket-wrap::after {
    content: '';
    position: absolute;
    right: 200px;
    top: 10px;
    bottom: 10px;
    border-right: 2px dashed rgba(255,255,255,0.25);
  }

  .ticket-left {
    flex: 1;
    display: flex;
    padding: 0;
    min-height: 260px;
  }

  .poster-section {
    width: 170px;
    min-width: 170px;
    background: #16213e;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 16px;
  }

  .poster-section img {
    width: 100%;
    max-height: 230px;
    object-fit: cover;
    border-radius: 8px;
    border: 2px solid #e94560;
  }

  .poster-placeholder {
    width: 100%;
    height: 200px;
    background: #16213e;
    border-radius: 8px;
    border: 2px solid #e94560;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 40px;
  }

  .info-section {
    flex: 1;
    padding: 20px 24px;
    display: flex;
    flex-direction: column;
    justify-content: center;
  }

  .movie-title {
    font-size: 22px;
    font-weight: 700;
    color: #e94560;
    margin: 0 0 14px 0;
    text-transform: uppercase;
    letter-spacing: 1px;
    line-height: 1.2;
  }

  .detail-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px 20px;
  }

  .detail-item {
    display: flex;
    flex-direction: column;
  }

  .detail-label {
    font-size: 9px;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: #888;
    margin-bottom: 2px;
  }

  .detail-value {
    font-size: 14px;
    font-weight: 600;
    color: #fff;
  }

  .seats-row {
    grid-column: 1 / -1;
  }

  .ticket-right {
    width: 200px;
    min-width: 200px;
    background: #16213e;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 20px 16px;
    text-align: center;
  }

  .qr-box img {
    width: 130px;
    height: 130px;
    border-radius: 8px;
    border: 2px solid #e94560;
    background: #fff;
    padding: 4px;
  }

  .booking-id {
    margin-top: 12px;
    font-size: 11px;
    font-weight: 700;
    color: #e94560;
    letter-spacing: 1px;
    word-break: break-all;
  }

  .amount-badge {
    margin-top: 8px;
    background: #e94560;
    color: #fff;
    padding: 4px 14px;
    border-radius: 20px;
    font-size: 14px;
    font-weight: 700;
  }

  .ticket-footer {
    width: 100%;
    text-align: center;
    font-size: 8px;
    color: #555;
    padding: 6px 0 0;
    letter-spacing: 0.5px;
  }

  @media print {
    body { background: #fff !important; }
    .ticket-wrap { box-shadow: none; }
    .print-format { padding: 0 !important; }
  }
</style>

<div class="ticket-wrap">
  <div class="ticket-left">
    <div class="poster-section">
      {% if poster %}
        <img src="{{ poster }}" alt="Movie Poster">
      {% else %}
        <div class="poster-placeholder">🎬</div>
      {% endif %}
    </div>
    <div class="info-section">
      <div class="movie-title">{{ doc.movie_title or '' }}</div>
      <div class="detail-grid">
        <div class="detail-item">
          <span class="detail-label">Date</span>
          <span class="detail-value">{{ frappe.utils.formatdate(doc.show_date, 'dd MMM yyyy') }}</span>
        </div>
        <div class="detail-item">
          <span class="detail-label">Time</span>
          <span class="detail-value">{{ frappe.utils.format_time(doc.start_time, 'hh:mm a') }}</span>
        </div>
        <div class="detail-item">
          <span class="detail-label">Theater</span>
          <span class="detail-value">{{ doc.theater or '' }}</span>
        </div>
        <div class="detail-item">
          <span class="detail-label">Screen</span>
          <span class="detail-value">{{ doc.screen or '' }}</span>
        </div>
        <div class="detail-item seats-row">
          <span class="detail-label">Seats</span>
          <span class="detail-value">{{ seats }}</span>
        </div>
        <div class="detail-item">
          <span class="detail-label">Guest</span>
          <span class="detail-value">{{ doc.customer_name or '' }}</span>
        </div>
        <div class="detail-item">
          <span class="detail-label">Qty</span>
          <span class="detail-value">{{ doc.number_of_seats }} seat{{ 's' if doc.number_of_seats != 1 else '' }}</span>
        </div>
      </div>
    </div>
  </div>
  <div class="ticket-right">
    {% if qr_url %}
      <div class="qr-box"><img src="{{ qr_url }}" alt="QR Code"></div>
    {% endif %}
    <div class="booking-id">{{ doc.name }}</div>
    <div class="amount-badge">{{ frappe.utils.fmt_money(doc.total_amount, currency='INR') }}</div>
    <div class="ticket-footer">Present this ticket at the entrance</div>
  </div>
</div>
